# Node shapes: X[text], X[[text]], X[(text)], X((text)), X{text}, X([text])
# We capture innermost text.
shape_patterns = [
    (r'\[\[(.+?)\]\]', 'subroutine'),
    (r'\[\((.+?)\)\]', 'cylinder/db'),
    (r'\(\((.+?)\)\)', 'circle'),
    (r'\[(.+?)\]',     'rect'),
    (r'\{(.+?)\}',     'rhombus'),
]
BREAK = '():;/\\<>"\''
problems=[]
for s,e in blocks:
    body = lines[s:e-1]
    for off,raw in enumerate(body):
        ln=s+1+off
        r = raw
        # node labels: process each shape match
        for pat,name in shape_patterns:
            for m in re.finditer(pat, r):
                txt=m.group(1)
                # if it's a quoted label, strip the quotes (quoted is safe)
                t=txt
                if t.startswith('"') and t.endswith('"'): 
                    inner=t[1:-1]
                    bad=[c for c in BREAK if c in inner]
                    if bad: problems.append((ln,name,'QUOTED-with-bad',txt,bad,raw.strip()))
                else:
                    bad=[c for c in BREAK if c in t]
                    if bad: problems.append((ln,name,'UNQUOTED',txt,bad,raw.strip()))
        # edge labels
